content.problemStatement:
You are given an Array and you have to output all possible subsets of that array.

For Example:
Let the array Arr = [1, 2, 3], It's possible subsets include:


{}
{1}
{2}
{3}
{1, 2}
{2, 3}
{1, 3}
{1, 2, 3}
**Note** - Print the subsets in sorted order.


Input Format

The first line of input will contain a single integer NNN, denoting the number of integers in the array.
The second line contains NNN integers.


Output Format
Output All the possible subsets of the given array.

code.C++:
class Solution {
public:
    // Recursive helper function
    vector<vector<int>> generateSubsets(vector<int>& arr, int index) {
        if (index == arr.size()) {
            return {{}};
        }

        // Get subsets for the rest of the array
        vector<vector<int>> subsets = generateSubsets(arr, index + 1);
        vector<vector<int>> newSubsets;

        for (auto subset : subsets) {
            newSubsets.push_back(subset); // Without current element
            subset.push_back(arr[index]); // Include current element
            newSubsets.push_back(subset);
        }

        return newSubsets;
    }

    vector<vector<int>> getAllSubsets(vector<int>& arr) {
        vector<vector<int>> subsets = generateSubsets(arr, 0);

        for (auto& subset : subsets) {
            sort(subset.begin(), subset.end());
        }

        sort(subsets.begin(), subsets.end());
        return subsets;
    }
};

