#include <stdio.h>
#include <stdlib.h>

// Sorts individual elements (already in your code)
int compareInt(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

// NEW: Sorts the subsets against each other in dictionary (lexicographical) order
int compareSubsets(const void *a, const void *b) {
    // Cast the void pointers to int pointers (representing our subsets)
    int *subsetA = *(int**)a;
    int *subsetB = *(int**)b;

    int i = 0;
    // Compare element by element until one subset ends (hits the -1 sentinel)
    while (subsetA[i] != -1 && subsetB[i] != -1) {
        if (subsetA[i] != subsetB[i]) {
            return subsetA[i] - subsetB[i];
        }
        i++;
    }

    // If they are identical up to this point, the shorter subset should come first
    if (subsetA[i] == -1 && subsetB[i] == -1) return 0;
    if (subsetA[i] == -1) return -1;
    return 1;
}

int** getAllSubsets(int *arr, int n, int *totalCount) {
    int total = 1 << n;
    *totalCount = total;
    int **allSubsets = malloc(total * sizeof(int*));

    for (int mask = 0; mask < total; mask++) {
        int *subset = malloc((n + 1) * sizeof(int)); // +1 for sentinel -1
        int k = 0;
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) subset[k++] = arr[i];
        }

        // Sort the individual subset
        qsort(subset, k, sizeof(int), compareInt);
        subset[k] = -1; // sentinel
        allSubsets[mask] = subset;
    }

    // FIX: Sort the entire array of subsets lexicographically before returning
    qsort(allSubsets, total, sizeof(int*), compareSubsets);

    return allSubsets;
}

code.Java:
class Solution {

    // Recursive function to generate subsets
    private List<List<Integer>> generateSubsets(int[] arr, int index) {
        if (index == arr.length) {
            List<List<Integer>> base = new ArrayList<>();
            base.add(new ArrayList<>()); // Empty subset
            return base;
        }

        List<List<Integer>> subsets = generateSubsets(arr, index + 1);
        List<List<Integer>> newSubsets = new ArrayList<>();

        for (List<Integer> subset : subsets) {
            newSubsets.add(new ArrayList<>(subset)); // Without current element

            List<Integer> withCurrent = new ArrayList<>(subset);
            withCurrent.add(arr[index]); // Include current element
            newSubsets.add(withCurrent);
        }

        return newSubsets;
    }

    public List<List<Integer>> getAllSubsets(int[] arr) {
        List<List<Integer>> subsets = generateSubsets(arr, 0);

        for (List<Integer> subset : subsets) {
            Collections.sort(subset);
        }

        subsets.sort((a, b) -> {
            int minLen = Math.min(a.size(), b.size());
            for (int i = 0; i < minLen; i++) {
                if (!a.get(i).equals(b.get(i))) {
                    return a.get(i) - b.get(i);
                }
            }
            return a.size() - b.size();
        });

        return subsets;
    }
}

