class Solution {
    // Recursive helper function
    generateSubsets(arr, index) {
        if (index === arr.length) {
            return [[]]; // Base case: empty subset
        }

        const subsets = this.generateSubsets(arr, index + 1);
        const newSubsets = [];

        for (const subset of subsets) {
            newSubsets.push([...subset]); // Without current element
            newSubsets.push([...subset, arr[index]]); // Include current element
        }

        return newSubsets;
    }

    getAllSubsets(arr) {
        let subsets = this.generateSubsets(arr, 0);

        subsets = subsets.map(subset => subset.sort((a, b) => a - b));

        subsets.sort((a, b) => {
            const minLen = Math.min(a.length, b.length);
            for (let i = 0; i < minLen; i++) {
                if (a[i] !== b[i]) return a[i] - b[i];
            }
            return a.length - b.length;
        });

        return subsets;
    }
}
